/**
 * LaunchLens — single eth_call for all launch detail page data.
 * Replaces 6+ individual RPC calls with one constructor-only sim.
 */

import { ethers } from 'ethers';

// ⚠ Keep in sync with solidty-contracts/artifacts/.../LaunchLens.json
const BYTECODE =
	'';

const LAUNCH_DATA_TYPE =
	'tuple(address token, address creator, uint8 curveType, uint8 state, uint8 effectiveState, uint256 softCap, uint256 hardCap, uint256 deadline, uint256 totalBaseRaised, uint256 tokensSold, uint256 tokensForCurve, uint256 tokensForLP, uint256 creatorAllocationBps, uint256 currentPrice, address usdt, uint256 startTimestamp, uint256 totalTokensRequired, uint256 totalTokensDeposited, uint256 totalBuyers, uint256 totalPurchases, uint256 maxBuyPerWallet, uint256 vestingCliff, uint256 vestingDuration, uint256 lockDurationAfterListing, uint256 minBuyUsdt, uint256 softCapBps, uint256 hardCapBps, uint256 refundStartTimestamp, uint256 vestingTotal, uint256 vestingClaimed, uint256 vestingClaimable, uint256 vestingNextClaim, string tokenName, string tokenSymbol, uint8 tokenDecimals, uint256 tokenTotalSupply)';

const USER_POSITION_TYPE = 'tuple(uint256 basePaid, uint256 tokensBought, uint256 tokenBalance)';

export interface LaunchLensData {
	token: string;
	creator: string;
	curveType: number;
	state: number;
	effectiveState: number;
	softCap: bigint;
	hardCap: bigint;
	deadline: number;
	totalBaseRaised: bigint;
	tokensSold: bigint;
	tokensForCurve: bigint;
	tokensForLP: bigint;
	creatorAllocationBps: number;
	currentPrice: bigint;
	usdt: string;
	startTimestamp: number;
	totalTokensRequired: bigint;
	totalTokensDeposited: bigint;
	totalBuyers: number;
	totalPurchases: number;
	maxBuyPerWallet: bigint;
	vestingCliff: number;
	vestingDuration: number;
	lockDurationAfterListing: number;
	minBuyUsdt: bigint;
	softCapBps: number;
	hardCapBps: number;
	refundStartTimestamp: number;
	vestingTotal: bigint;
	vestingClaimed: bigint;
	vestingClaimable: bigint;
	vestingNextClaim: number;
	tokenName: string;
	tokenSymbol: string;
	tokenDecimals: number;
	tokenTotalSupply: bigint;
}

export interface UserPosition {
	basePaid: bigint;
	tokensBought: bigint;
	tokenBalance: bigint;
}

export async function queryLaunchLens(
	provider: ethers.Provider,
	launchAddress: string,
	userAddress: string = ethers.ZeroAddress,
): Promise<{ launch: LaunchLensData; user: UserPosition }> {
	const abiCoder = ethers.AbiCoder.defaultAbiCoder();
	const args = abiCoder.encode(
		['address', 'address'],
		[launchAddress, userAddress],
	);

	const raw = await provider.call({
		data: BYTECODE + args.slice(2),
		gasLimit: 15_000_000,
	});

	const decoded = abiCoder.decode([LAUNCH_DATA_TYPE, USER_POSITION_TYPE], raw);

	const ld = decoded[0];
	const launch: LaunchLensData = {
		token: ld.token,
		creator: ld.creator,
		curveType: Number(ld.curveType),
		state: Number(ld.state),
		effectiveState: Number(ld.effectiveState),
		softCap: ld.softCap,
		hardCap: ld.hardCap,
		deadline: Number(ld.deadline),
		totalBaseRaised: ld.totalBaseRaised,
		tokensSold: ld.tokensSold,
		tokensForCurve: ld.tokensForCurve,
		tokensForLP: ld.tokensForLP,
		creatorAllocationBps: Number(ld.creatorAllocationBps),
		currentPrice: ld.currentPrice,
		usdt: ld.usdt,
		startTimestamp: Number(ld.startTimestamp),
		totalTokensRequired: ld.totalTokensRequired,
		totalTokensDeposited: ld.totalTokensDeposited,
		totalBuyers: Number(ld.totalBuyers),
		totalPurchases: Number(ld.totalPurchases),
		maxBuyPerWallet: ld.maxBuyPerWallet,
		vestingCliff: Number(ld.vestingCliff),
		vestingDuration: Number(ld.vestingDuration),
		lockDurationAfterListing: Number(ld.lockDurationAfterListing),
		minBuyUsdt: ld.minBuyUsdt,
		softCapBps: Number(ld.softCapBps),
		hardCapBps: Number(ld.hardCapBps),
		refundStartTimestamp: Number(ld.refundStartTimestamp),
		vestingTotal: ld.vestingTotal,
		vestingClaimed: ld.vestingClaimed,
		vestingClaimable: ld.vestingClaimable,
		vestingNextClaim: Number(ld.vestingNextClaim),
		tokenName: ld.tokenName,
		tokenSymbol: ld.tokenSymbol,
		tokenDecimals: Number(ld.tokenDecimals),
		tokenTotalSupply: ld.tokenTotalSupply,
	};

	const up = decoded[1];
	const user: UserPosition = {
		basePaid: up.basePaid,
		tokensBought: up.tokensBought,
		tokenBalance: up.tokenBalance,
	};

	return { launch, user };
}
